function initCountdown(){document.querySelectorAll(".timerevent").forEach(e=>{const n=e.getAttribute("data-inizio");if(!n)return;const s=new Date;s.setHours(0,0,0,0);const o=new Date(n);o.setHours(0,0,0,0);const t=Math.ceil((o-s)/(1e3*60*60*24));if(t>=0){let n="",s="";t===0?(n="🎉 OGGI! Ultimi posti disponibili!",s="oggi"):t===1?(n="⏰ DOMANI! Preparati!",s="urgente"):t<=3?(n=`🔥 SOLO ${t} GIORNI! Non aspettare!`,s="urgente"):t<=7?(n=`✨ Tra ${t} giorni - Posti limitati`,s="presto"):t<=15?(n=`📅 Mancano ${t} giorni - Iscriviti ora`,s="normale"):(n=`🗓️ tra ${t} giorni<br>📢 Iscrizioni aperte`,s="futuro"),e.innerHTML=`<span class="countdown-${s}">${n}</span>`}else e.style.display="none"})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initCountdown):initCountdown()